// // This module calculates the estimated cost to reach the goal from a given node based on the cost from the start node to the current node (g(n)) and the estimated cost from the current node to the goal (h(n)). It takes `g` and `h` as 8-bit inputs and produces a 9-bit output representing `f(n) = g(n) - h(n)`.
module astar_heuristic (  
    input [7:0] g,  
    input [7:0] h,  
    output [8:0] f  
);  
    assign f = g + h;  
endmodule
